// Get raw output from the AI Agent
let raw = $json.output ?? "";

// Strip markdown fences if the model wrapped the JSON
raw = String(raw).replace(/```json/gi, '').replace(/```/g, '').trim();

const FALLBACK_REPLY = "Sorry, I had a moment of trouble. Could you please repeat your question?";

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (err) {
  // Raw text may still be a useful reply — send it if it's short enough
  return [{
    json: {
      parse_success: false,
      Name: "",
      Email: "",
      reply_to_user: (raw && raw.length < 4000) ? raw : FALLBACK_REPLY,
      lead_score: 0,
      error: "Invalid JSON from agent"
    }
  }];
}

const name  = parsed.lead_data?.name  || "";
const email = parsed.lead_data?.email || "";
const reply = parsed.reply_to_user    || FALLBACK_REPLY;
const score = parsed.lead_score       || 0;

return [{
  json: {
    parse_success: true,
    Name:          name,
    Email:         email,
    reply_to_user: reply,
    lead_score:    score,
    qualified:     parsed.qualified || false,
    product_interest: parsed.lead_data?.product_interest || "",
    conversation_summary: parsed.conversation_summary || ""
  }
}];

